            margin-top: 15px;
        }
        /* Game Section */
        .game-section {
            display: none;
            animation: fadeIn 0.5s ease-out;
        }
        .game-section.active {
            display: block;
        }
        .game-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
