                { word: "spa", translation: "温泉浴场", options: ["游泳池", "温泉浴场", "浴室", "澡堂", "水疗"] },
                { word: "pool", translation: "游泳池", options: ["池塘", "游泳池", "湖泊", "河流", "水池"] },
                { word: "bath", translation: "浴缸", options: ["洗手池", "浴缸", "马桶", "淋浴", "浴盆"] },
                { word: "shower", translation: "淋浴", options: ["浴缸", "淋浴", "洗手池", "马桶", "花洒"] },
                { word: "sink", translation: "洗手池", options: ["浴缸", "洗手池", "马桶", "淋浴", "水槽"] },
                { word: "toilet", translation: "马桶", options: ["洗手池", "马桶", "浴缸", "淋浴", "坐便器"] },
                { word: "faucet", translation: "水龙头", options: ["水管", "水龙头", "阀门", "开关", "水嘴"] },
                { word: "tap", translation: "水龙头", options: ["水管", "水龙头", "阀门", "开关", "塞子"] }
            ]
        };
        const characters = {
            ryder: { name: "莱德", theme: "command", themeName: "指令英语", className: "ryder" },
            chase: { name: "阿奇", theme: "vehicle", themeName: "交通工具", className: "chase" },
            skye: { name: "天天", theme: "sky", themeName: "航空天气", className: "skye" },
            rubble: { name: "小砾", theme: "construction", themeName: "工程建筑", className: "rubble" },
            marshall: { name: "毛毛", theme: "fire", themeName: "消防救援", className: "marshall" },
            zuma: { name: "路马", theme: "water", themeName: "水上救援", className: "zuma" }
        };
        let currentDifficulty = null;
        let currentCharacter = null;
        let currentTheme = null;
        let currentQuestionIndex = 0;
        let score = 0;
        let questions = [];
        let answered = false;
        let earnedBadges = new Set();
        let isPaused = false;
        // DOM Elements
        const loading = document.getElementById('loading');
        const difficultySection = document.getElementById('difficultySection');
        const characterSection = document.getElementById('characterSection');
        const gameSection = document.getElementById('gameSection');
        const resultSection = document.getElementById('resultSection');
        const toCharacterBtn = document.getElementById('toCharacterBtn');
        const startGameBtn = document.getElementById('startGameBtn');
        const backToDifficultyBtn = document.getElementById('backToDifficultyBtn');
        const scoreDisplay = document.getElementById('scoreDisplay');
        const questionText = document.getElementById('questionText');
        const questionHint = document.getElementById('questionHint');
        const optionsGrid = document.getElementById('optionsGrid');
        const speakerBtn = document.getElementById('speakerBtn');
        const currentCharacterBadge = document.getElementById('currentCharacterBadge');
        const currentCharacterName = document.getElementById('currentCharacterName');
        const currentCharacterTheme = document.getElementById('currentCharacterTheme');
        const finalScore = document.getElementById('finalScore');
        const backToCharactersBtn = document.getElementById('backToCharactersBtn');
        const playAgainBtn = document.getElementById('playAgainBtn');
        const progressBar = document.getElementById('progressBar');
        const currentQuestionSpan = document.getElementById('currentQuestion');
        const totalQuestionsSpan = document.getElementById('totalQuestions');
        const badgeDisplay = document.getElementById('badgeDisplay');
        const badgesGrid = document.getElementById('badgesGrid');
        const homeBtn = document.getElementById('homeBtn');
        const pauseBtn = document.getElementById('pauseBtn');
        const pauseModal = document.getElementById('pauseModal');
        const resumeBtn = document.getElementById('resumeBtn');
        const pauseHomeBtn = document.getElementById('pauseHomeBtn');
        // Initialize
        window.addEventListener('load', () => {
            setTimeout(() => {
                loading.classList.add('hidden');
                Object.keys(characterImages).forEach(key => {
                    const avatar = document.getElementById(`avatar-${key}`);
                    if (avatar) {
                        avatar.style.backgroundImage = `url('${characterImages[key]}')`;
                    }
                });
                loadBadges();
            }, 1000);
        });
        // Load badges from localStorage
        function loadBadges() {
            const saved = localStorage.getItem('pawPatrolBadges');
            if (saved) {
                earnedBadges = new Set(JSON.parse(saved));
            }
            updateBadgeDisplay();
        }
        // Save badges to localStorage
        function saveBadges() {
            localStorage.setItem('pawPatrolBadges', JSON.stringify([...earnedBadges]));
        }
        // Update badge display
        function updateBadgeDisplay() {
            badgesGrid.innerHTML = '';
            const allThemes = ['command', 'vehicle', 'sky', 'construction', 'fire', 'water'];
            const icons = ['🚗', '✈️', '🏗️', '🚒', '🚤', '⭐'];
            allThemes.forEach((theme, index) => {
                const badgeItem = document.createElement('div');
                badgeItem.className = 'badge-item';
                badgeItem.textContent = icons[index];
                if (earnedBadges.has(theme)) {
                    badgeItem.classList.add('earned');
                }
                badgesGrid.appendChild(badgeItem);
            });
            if (earnedBadges.size > 0) {
                badgeDisplay.classList.add('show');
            }
        }
        // Award badge
        function awardBadge(theme) {
            if (!earnedBadges.has(theme)) {
                earnedBadges.add(theme);
                saveBadges();
                updateBadgeDisplay();
            }
        }
        // Event Listeners
        document.querySelectorAll('.difficulty-card').forEach(card => {
            card.addEventListener('click', () => selectDifficulty(card));
        });
        toCharacterBtn.addEventListener('click', () => {
            difficultySection.classList.remove('active');
            characterSection.classList.add('active');
        });
        document.querySelectorAll('.character-card').forEach(card => {
            card.addEventListener('click', () => selectCharacter(card));
        });
        startGameBtn.addEventListener('click', startGame);
        speakerBtn.addEventListener('click', speakCurrentWord);
        backToDifficultyBtn.addEventListener('click', () => {
            characterSection.classList.remove('active');
            difficultySection.classList.add('active');
        });
        backToCharactersBtn.addEventListener('click', backToCharacters);
        playAgainBtn.addEventListener('click', restartGame);
        // Home and Pause buttons
        homeBtn.addEventListener('click', goHome);
        pauseBtn.addEventListener('click', togglePause);
        resumeBtn.addEventListener('click', togglePause);
        pauseHomeBtn.addEventListener('click', () => {
            togglePause();
            goHome();
        });
        // Select difficulty
        function selectDifficulty(cardElement) {
            document.querySelectorAll('.difficulty-card').forEach(c => c.classList.remove('selected'));
            cardElement.classList.add('selected');
            currentDifficulty = cardElement.dataset.difficulty;
            toCharacterBtn.disabled = false;
        }
        // Select character
        function selectCharacter(cardElement) {
            document.querySelectorAll('.character-card').forEach(c => c.classList.remove('selected'));
            cardElement.classList.add('selected');
            const characterKey = cardElement.dataset.character;
            currentCharacter = characters[characterKey];
            currentTheme = cardElement.dataset.theme;
            startGameBtn.disabled = false;
        }
        // Get options count based on difficulty
        function getOptionsCount() {
            switch(currentDifficulty) {
                case 'easy': return 3;
                case 'hard': return 5;
                default: return 4;
            }
        }
        // Start game
        function startGame() {
            characterSection.classList.remove('active');
            gameSection.classList.add('active');
            badgeDisplay.classList.add('show');
            currentCharacterBadge.style.backgroundImage = `url('${characterImages[currentCharacter.className]}')`;
            currentCharacterName.textContent = currentCharacter.name;
            currentCharacterTheme.textContent = currentCharacter.themeName;
            score = 0;
            currentQuestionIndex = 0;
            questions = [...vocabulary[currentTheme]];
            questions.sort(() => Math.random() - 0.5);
            questions = questions.slice(0, 10);
            totalQuestionsSpan.textContent = questions.length;
            updateScore();
            updateProgress();
            showQuestion();
        }
        // Show current question
        function showQuestion() {
            if (currentQuestionIndex >= questions.length) {
                endGame();
                return;
            }
            answered = false;
            const question = questions[currentQuestionIndex];
            questionText.textContent = question.word;
            questionHint.textContent = '是什么意思？';
            const optionsCount = getOptionsCount();
            const options = [...question.options];
            // Ensure correct answer is included
            if (!options.includes(question.translation)) {
                options[optionsCount - 1] = question.translation;
            }
            options.sort(() => Math.random() - 0.5);
            const finalOptions = options.slice(0, optionsCount);
            // Make sure correct answer is in final selection
            if (!finalOptions.includes(question.translation)) {
                finalOptions[optionsCount - 1] = question.translation;
            }
            optionsGrid.innerHTML = '';
            finalOptions.forEach(option => {
                const optionCard = document.createElement('div');
                optionCard.className = 'option-card';
                optionCard.innerHTML = `<div class="option-text">${option}</div>`;
                optionCard.addEventListener('click', () => checkAnswer(optionCard, option, question.translation));
                optionsGrid.appendChild(optionCard);
            });
            // Auto-play sound for easy mode
            if (currentDifficulty === 'easy') {
                setTimeout(speakCurrentWord, 300);
            }
        }
        // Check answer
        function checkAnswer(optionElement, selected, correct) {
            if (answered || isPaused) return;
            answered = true;
            if (selected === correct) {
                optionElement.classList.add('correct');
                score++;
                updateScore();
                // Play happy sound effect
                playSoundEffect('correct');
                setTimeout(() => {
                    currentQuestionIndex++;
                    updateProgress();
                    showQuestion();
                }, 800);
            } else {
                optionElement.classList.add('wrong');
                Array.from(optionsGrid.children).forEach(card => {
                    if (card.textContent.trim() === correct) {
                        card.classList.add('correct');
                    }
                });
                playSoundEffect('wrong');
                setTimeout(() => {
                    currentQuestionIndex++;
                    updateProgress();
                    showQuestion();
                }, 1200);
            }
        }
        // Play sound effect
        function playSoundEffect(type) {
            // Simple beep using Web Audio API
            const audioContext = new (window.AudioContext || window.webkitAudioContext)();
            const oscillator = audioContext.createOscillator();
            const gainNode = audioContext.createGain();
            oscillator.connect(gainNode);
            gainNode.connect(audioContext.destination);
            if (type === 'correct') {
                oscillator.frequency.value = 800;
                gainNode.gain.setValueAtTime(0.3, audioContext.currentTime);
                oscillator.start(audioContext.currentTime);
                oscillator.stop(audioContext.currentTime + 0.1);
            } else {
                oscillator.frequency.value = 200;
                gainNode.gain.setValueAtTime(0.3, audioContext.currentTime);
                oscillator.start(audioContext.currentTime);
                oscillator.stop(audioContext.currentTime + 0.2);
            }
        }
        // Update score display
        function updateScore() {
            scoreDisplay.textContent = `${score} / ${questions.length}`;
        }
        // Update progress
        function updateProgress() {
            const progress = ((currentQuestionIndex + 1) / questions.length) * 100;
            progressBar.style.width = `${progress}%`;
            currentQuestionSpan.textContent = currentQuestionIndex + 1;
        }
        // End game
        function endGame() {
            gameSection.classList.remove('active');
            resultSection.classList.add('active');
            finalScore.textContent = score;
            // Award badge if score >= 8
            if (score >= 8) {
                awardBadge(currentTheme);
                createConfetti();
            }
        }
        // Back to character selection
        function backToCharacters() {
            resultSection.classList.remove('active');
            characterSection.classList.add('active');
            startGameBtn.disabled = !currentCharacter;
        }
        // Restart game with same character
        function restartGame() {
            resultSection.classList.remove('active');
            gameSection.classList.add('active');
            startGame();
        }
        // Speak current word
        function speakCurrentWord() {
            if (!('speechSynthesis' in window)) {
                alert('您的浏览器不支持语音朗读功能');
                return;
            }
            if (answered || isPaused) return;
            const question = questions[currentQuestionIndex];
            const utterance = new SpeechSynthesisUtterance(question.word);
            utterance.lang = 'en-US';
            utterance.rate = 0.8;
            utterance.pitch = 1;
            speechSynthesis.cancel();
            speechSynthesis.speak(utterance);
        }
        // Create confetti effect
        function createConfetti() {
            const colors = ['#2E5CAB', '#FFD100', '#ED2633', '#39B54A', '#5B8BDF', '#E91E63'];
            const container = document.body;
            for (let i = 0; i < 50; i++) {
                setTimeout(() => {
                    const confetti = document.createElement('div');
                    confetti.className = 'confetti';
                    confetti.style.left = Math.random() * 100 + 'vw';
                    confetti.style.background = colors[Math.floor(Math.random() * colors.length)];
                    confetti.style.left = `${Math.random() * 100}%`;
                    confetti.style.animationDuration = `${2 + Math.random() * 2}s`;
                    confetti.style.animationDelay = `${Math.random() * 1}s`;
                    container.appendChild(confetti);
                    setTimeout(() => confetti.remove(), 3000);
                }, i * 30);
            }
        }
        // Go to home
        function goHome() {
            // Cancel any ongoing speech
            if ('speechSynthesis' in window) {
                speechSynthesis.cancel();
            }
            // Reset game state
            currentDifficulty = null;
            currentCharacter = null;
            currentTheme = null;
            currentQuestionIndex = 0;
            score = 0;
            questions = [];
            answered = false;
            isPaused = false;
            // Hide all sections
            gameSection.classList.remove('active');
            resultSection.classList.remove('active');
            characterSection.classList.remove('active');
            // Show difficulty section
            difficultySection.classList.add('active');
            // Reset difficulty selection
            document.querySelectorAll('.difficulty-card').forEach(c => c.classList.remove('selected'));
            toCharacterBtn.disabled = true;
            // Reset character selection
            document.querySelectorAll('.character-card').forEach(c => c.classList.remove('selected'));
            startGameBtn.disabled = true;
            // Hide pause modal
            pauseModal.classList.remove('show');
        }
        // Toggle pause
        function togglePause() {
            isPaused = !isPaused;
            if (isPaused) {
                pauseModal.classList.add('show');
                // Cancel any ongoing speech
                if ('speechSynthesis' in window) {
                    speechSynthesis.cancel();
                }
            } else {
                pauseModal.classList.remove('show');
            }
        }
    </script>
