<body>
    <div class="container">
        <!-- 头部 -->
        <div class="header">
            <h1>🐾 汪汪队英语乐园</h1>
            <p>和汪汪队一起快乐学英语！</p>
        </div>

        <!-- 进度条 -->
        <div class="progress-container">
            <div class="progress-info">
                <span id="levelInfo">第 1 关 / 共 10 关</span>
                <span id="scoreInfo">得分：0</span>
            </div>
            <div class="progress-bar">
                <div class="progress-fill" id="progressFill" style="width: 10%;"></div>
            </div>
        </div>

        <!-- 主内容区 -->
        <div class="content" id="gameContent">
            <!-- 动态内容将在这里显示 -->
        </div>

        <!-- 底部导航 -->
        <div class="bottom-nav">
            <button class="nav-btn active" onclick="showMenu()">🏠 首页</button>
            <button class="nav-btn" onclick="continueGame()">▶️ 继续</button>
            <button class="nav-btn" onclick="showResults()">📊 成绩</button>
        </div>
    </div>
    <script>
        // 游戏数据
        let currentLevel = 1;
        let score = 0;
        let totalQuestions = 10;
        let currentQuestion = null;
        let gameMode = 'menu'; // menu, playing, result

        // 题库
        const questionBank = [
            {
                type: 'letter',
                question: '哪个是字母 "A"?',
                emoji: '🅰️',
                options: ['A', 'B', 'D'],
                answer: 0
            },
            {
                type: 'word',
                question: '"Apple" 是什么意思？',
                emoji: '🍎',
                options: ['香蕉', '苹果', '橙子'],
                answer: 1
            },
            {
                type: 'listening',
                question: '听音辨物：这是哪种动物？',
                emoji: '🐶',
                audio: 'dog',
                options: ['猫', '狗', '鸟'],
                answer: 1
            },
            {
                type: 'match',
                question: '"Cat" 对应哪个图片？',
                emoji: '❓',
                options: ['🐱', '🐶', '🐰'],
                answer: 0
            },
            {
                type: 'word',
                question: '"Banana" 是什么颜色？',
                emoji: '🍌',
                options: ['红色', '黄色', '蓝色'],
                answer: 1
            }
        ];

        // 初始化游戏
        function initGame() {
            showMenu();
        }

        // 显示菜单
        function showMenu() {
            gameMode = 'menu';
            updateNav();
            const content = document.getElementById('gameContent');
            content.innerHTML = `
                <div class="menu-grid">
                    <button class="menu-item blue" onclick="startGame('letter')">
                        <span class="icon">🔤</span>
                        学字母
                    </button>
                    <button class="menu-item green" onclick="startGame('word')">
                        <span class="icon">📝</span>
                        学单词
                    </button>
                    <button class="menu-item orange" onclick="startGame('listening')">
                        <span class="icon">🎧</span>
                        练听力
                    </button>
                    <button class="menu-item" onclick="startGame('match')">
                        <span class="icon">🧩</span>
                        配对游戏
                    </button>
                </div>
            `;
        }

        // 开始游戏
        function startGame(mode) {
            gameMode = 'playing';
            currentLevel = 1;
            score = 0;
            updateProgress();
            updateNav();
            showQuestion(mode);
        }

        // 显示问题
        function showQuestion(mode) {
            const questions = questionBank.filter(q => q.type === mode);
            const question = questions[Math.floor(Math.random() * questions.length)];
            currentQuestion = question;

            const content = document.getElementById('gameContent');
            content.innerHTML = `
                <div class="question-card">
                    <div class="question-text">${question.question}</div>
                    <div class="question-image">${question.emoji}</div>
                </div>
                <div class="options-grid">
                    ${question.options.map((opt, index) => `
                        <button class="option-btn" onclick="checkAnswer(${index})">
                            ${opt}
                        </button>
                    `).join('')}
                </div>
            `;
        }

        // 检查答案
        function checkAnswer(index) {
            const buttons = document.querySelectorAll('.option-btn');
            if (index === currentQuestion.answer) {
                buttons[index].classList.add('correct');
                score += 10;
                setTimeout(() => {
                    currentLevel++;
                    if (currentLevel > totalQuestions) {
                        showResults();
                    } else {
                        updateProgress();
                        showQuestion(currentQuestion.type);
                    }
                }, 1000);
            } else {
                buttons[index].classList.add('wrong');
                setTimeout(() => {
                    buttons[index].classList.remove('wrong');
                }, 500);
            }
            updateProgress();
        }

        // 更新进度
        function updateProgress() {
            document.getElementById('levelInfo').textContent = `第 ${currentLevel} 关 / 共 ${totalQuestions} 关`;
            document.getElementById('scoreInfo').textContent = `得分：${score}`;
            const progress = (currentLevel / totalQuestions) * 100;
            document.getElementById('progressFill').style.width = `${progress}%`;
        }

        // 显示结果
        function showResults() {
            gameMode = 'result';
            updateNav();
            const percentage = (score / (totalQuestions * 10)) * 100;
            let emoji, message;
            if (percentage >= 90) {
                emoji = '🏆';
                message = '太棒了！你真是英语小天才！继续保持！';
            } else if (percentage >= 70) {
                emoji = '🌟';
                message = '很不错！继续加油，你会更棒的！';
            } else if (percentage >= 50) {
                emoji = '💪';
                message = '不错哦！多练习几次会更好！';
            } else {
                emoji = '📚';
                message = '没关系，我们一起再学习一次吧！';
            }

            const content = document.getElementById('gameContent');
            content.innerHTML = `
                <div class="result-card">
                    <div class="result-emoji">${emoji}</div>
                    <div class="result-title">完成！</div>
                    <div class="result-score">${score} 分</div>
                    <div class="result-message">${message}</div>
                    <div class="btn-group">
                        <button class="btn btn-primary" onclick="showMenu()">🏠 返回首页</button>
                        <button class="btn btn-success" onclick="startGame('${currentQuestion?.type || 'word'}')">🔄 再来一次</button>
                    </div>
                </div>
            `;
        }

        // 继续游戏
        function continueGame() {
            if (gameMode === 'result') {
                startGame(currentQuestion?.type || 'word');
            } else if (gameMode === 'menu') {
                alert('请先选择一个游戏模式哦！😊');
            }
        }

        // 更新导航
        function updateNav() {
            const navBtns = document.querySelectorAll('.nav-btn');
            navBtns[0].classList.toggle('active', gameMode === 'menu');
            navBtns[1].classList.toggle('active', gameMode === 'playing');
            navBtns[2].classList.toggle('active', gameMode === 'result');
        }

        // 页面加载完成后初始化
        window.onload = initGame;
    </script>
</body>
</html>
