        .flashcard-translation {
            font-size: 20px;
            opacity: 0.9;
        }

        .flashcard-hint {
            font-size: 14px;
            opacity: 0.8;
            margin-top: 10px;
        }

        /* 配对游戏 */
        .matching-grid {
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: 10px;
            margin-top: 15px;
        }

        .matching-card {
            background: white;
            border: 3px solid #e0e0e0;
            border-radius: 12px;
            padding: 15px 10px;
            text-align: center;
            cursor: pointer;
            transition: all 0.3s ease;
            font-size: 16px;
            font-weight: 500;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-height: 80px;
