            background: #f0fff4;
        }

        .matching-emoji {
            font-size: 28px;
            margin-bottom: 8px;
        }

        /* 拼写游戏 */
        .spelling-area {
            background: #f8f9fa;
            border-radius: 16px;
            padding: 20px 15px;
            text-align: center;
            margin-bottom: 20px;
        }

        .spelling-hint {
            font-size: 16px;
            color: #666;
            margin-bottom: 15px;
        }

        .spelling-emoji {
            font-size: 50px;
            margin: 15px 0;
        }

        .letter-bank {
            display: flex;
            gap: 8px;
            justify-content: center;
            margin-bottom: 15px;
            flex-wrap: wrap;
        }

        .letter-tile {
            width: 45px;
            height: 45px;
            border: 2px solid #e0e0e0;
            border-radius: 10px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 22px;
            font-weight: bold;
            background: white;
            cursor: pointer;
            transition: all 0.3s ease;
        }

        .letter-tile.selected {
            background: #667eea;
            color: white;
            border-color: #667eea;
        }

        .letter-tile.used {
            background: #ccc;
            color: #999;
            border-color: #ccc;
            cursor: not-allowed;
        }

        .current-spelling {
            font-size: 18px;
            color: #666;
            margin-bottom: 15px;
            min-height: 25px;
            padding: 10px;
            background: white;
            border-radius: 8px;
        }

        /* 听力游戏 */
        .listening-area {
            text-align: center;
            padding: 25px 15px;
            background: #f8f9fa;
            border-radius: 16px;
            margin-bottom: 20px;
        }

        .play-btn {
            display: inline-block;
            width: 80px;
            height: 80px;
            border-radius: 50%;
