        .play-btn:active {
            transform: scale(0.95);
        }

        .listening-options {
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: 10px;
            margin-top: 20px;
        }

        .listening-option {
            padding: 15px;
            border: 3px solid #e0e0e0;
            border-radius: 12px;
            background: white;
            cursor: pointer;
            transition: all 0.3s ease;
            font-size: 16px;
            text-align: center;
        }

        .listening-option:active {
            transform: scale(0.95);
        }

        /* 结果统计 */
        .result-stats {
            text-align: center;
            padding: 30px 20px;
        }

        .result-title {
