        .stat-item {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 3px;
        }

        .stat-value {
            font-size: 18px;
            font-weight: bold;
            color: #667eea;
        }

        .stat-label {
            color: #666;
            font-size: 11px;
        }

