            color: #333;
            margin-bottom: 8px;
        }

        .info-content {
            font-size: 13px;
            color: #666;
            line-height: 1.5;
        }

        /* 欢迎信息 */
        .welcome-card {
            background: linear-gradient(135deg, #f8f9fa 0%, #f0f2f5 100%);
            border-radius: 16px;
            padding: 25px 20px;
            text-align: center;
            margin-bottom: 20px;
        }

