                    { en: 'Friend', zh: '朋友', emoji: '👫' },
                    { en: 'Teacher', zh: '老师', emoji: '👩‍🏫' }
                ]
            }
        };

        // 徽章列表
        const badgesList = [
            { id: 'first_game', name: '初次体验', icon: '🎮' },
            { id: 'streak_5', name: '五连胜', icon: '🔥' },
            { id: 'streak_10', name: '十连胜', icon: '⚡' },
            { id: 'score_100', name: '百分达人', icon: '💯' },
            { id: 'score_500', name: '五百分', icon: '🌟' },
            { id: 'spelling_master', name: '拼写大师', icon: '✍️' },
            { id: 'matching_champ', name: '配对冠军', icon: '🧩' },
            { id: 'animals_expert', name: '动物专家', icon: '🐾' },
            { id: 'fruits_expert', name: '水果专家', icon: '🍎' },
            { id: 'colors_expert', name: '色彩大师', icon: '🎨' },
            { id: 'all_themes', name: '全能达人', icon: '🏆' },
            { id: 'vocab_master', name: '词汇达人', icon: '📚' }
        ];

        // 统计总单词数
        let totalWordCount = 0;
        Object.keys(contentLibrary.words).forEach(theme => {
            totalWordCount += contentLibrary.words[theme].length;
        });
        gameData.totalWords = totalWordCount;

        // 初始化游戏
        function initGame() {
            renderThemeSelector();
            showWelcome();
            updateStats();
        }

        // 渲染主题选择器
        function renderThemeSelector() {
            const container = document.getElementById('themeSelector');
            container.innerHTML = contentLibrary.themes.map(theme => `
                <button class="theme-btn ${gameData.currentTheme === theme.id ? 'active' : ''}" 
                        onclick="selectTheme('${theme.id}')">
                    ${theme.icon} ${theme.name}
                </button>
            `).join('');
        }

        // 选择主题
        function selectTheme(themeId) {
            gameData.currentTheme = themeId;
            renderThemeSelector();
            if (gameData.gameState === 'menu') {
                showMainMenu();
            } else {
                // 更新当前游戏
                if (gameData.currentMode) {
                    startGame(gameData.currentMode);
                }
            }
            checkThemeBadges();
        }

        // 显示欢迎页
        function showWelcome() {
            gameData.gameState = 'welcome';
            const content = document.getElementById('gameContent');
            content.innerHTML = `
                <div class="welcome-card">
                    <div class="welcome-emoji">🐾👋</div>
                    <div class="welcome-title">欢迎来到汪汪队英语乐园！</div>
                    <div class="welcome-text">
                        和汪汪队一起快乐学英语！<br>
                        这里有有趣的游戏、可爱的图标和满满的成就感！<br>
                        让小朋友在玩乐中轻松掌握英语单词！
                    </div>
                    <div class="word-count">
                        📚 总计 ${gameData.totalWords} 个单词，8大主题！
                    </div>
                </div>
                <div class="game-modes">
                    ${contentLibrary.gameModes.map(mode => `
                        <div class="mode-card ${gameData.currentMode === mode.id ? 'active' : ''}" 
                             onclick="selectMode('${mode.id}')">
                            <div class="mode-icon">${mode.icon}</div>
                            <div class="mode-name">${mode.name}</div>
                            <div class="mode-desc">${mode.desc}</div>
                        </div>
                    `).join('')}
                </div>
                <div class="btn-group">
                    <button class="btn btn-primary" onclick="startGame('${gameData.currentMode}')">
                        🚀 开始学习
                    </button>
                    <button class="btn btn-warning" onclick="showBadges()">
                        🏆 查看徽章收藏
                    </button>
                </div>
            `;
            awardBadge('first_game');
            updateStats();
        }

        // 显示主菜单
        function showMainMenu() {
            gameData.gameState = 'menu';
            const content = document.getElementById('gameContent');
            content.innerHTML = `
                <div class="game-info">
                    <div class="info-title">📖 当前主题：${getCurrentThemeName()}</div>
                    <div class="info-content">
                        共有 <strong>${contentLibrary.words[gameData.currentTheme].length}</strong> 个单词
                    </div>
                </div>
                <div class="game-modes">
                    ${contentLibrary.gameModes.map(mode => `
                        <div class="mode-card ${gameData.currentMode === mode.id ? 'active' : ''}" 
                             onclick="selectMode('${mode.id}')">
                            <div class="mode-icon">${mode.icon}</div>
                            <div class="mode-name">${mode.name}</div>
                            <div class="mode-desc">${mode.desc}</div>
                        </div>
                    `).join('')}
                </div>
                <div class="btn-group">
                    <button class="btn btn-primary" onclick="startGame('${gameData.currentMode}')">
                        🚀 开始游戏
                    </button>
                    <button class="btn btn-warning" onclick="showBadges()">
                        🏆 我的徽章
                    </button>
                    <button class="btn" onclick="showWelcome()">
                        🏠 返回首页
                    </button>
                </div>
            `;
        }

        // 获取当前主题名称
        function getCurrentThemeName() {
            const theme = contentLibrary.themes.find(t => t.id === gameData.currentTheme);
            return theme ? theme.icon + ' ' + theme.name : '未知';
        }

        // 选择游戏模式
        function selectMode(modeId) {
            gameData.currentMode = modeId;
            if (gameData.gameState === 'menu') {
                showMainMenu();
            }
        }

        // 开始游戏
        function startGame(mode) {
            gameData.gameState = 'playing';
            gameData.currentMode = mode;

            awardBadge('first_game');
            checkAllThemesBadge();

            switch(mode) {
                case 'flashcard':
                    showFlashcardGame();
                    break;
                case 'matching':
                    showMatchingGame();
                    break;
                case 'spelling':
                    showSpellingGame();
                    break;
                case 'listening':
                    showListeningGame();
                    break;
            }
        }

        // 获取随机单词
        function getRandomWord() {
            const words = contentLibrary.words[gameData.currentTheme];
            return words[Math.floor(Math.random() * words.length)];
        }

        // 闪卡游戏
        function showFlashcardGame() {
            const word = getRandomWord();
            let hint = '';
            if (word.color) hint = `颜色：${word.color}`;
            if (word.count) hint = `数量：${word.count}`;

            const content = document.getElementById('gameContent');
            content.innerHTML = `
                <div class="game-info">
                    <div class="info-title">📖 闪卡学习</div>
                    <div class="info-content">
                        认出单词后点击 "我认识"，不认得出点击 "再学一次"
                    </div>
                </div>
                <div class="flashcard">
                    <div class="flashcard-emoji">${word.emoji}</div>
                    <div class="flashcard-word">${word.en}</div>
                    <div class="flashcard-translation">${word.zh}</div>
                    ${hint ? `<div class="flashcard-hint">${hint}</div>` : ''}
                </div>
                <div class="btn-group">
                    <div class="btn-row">
                        <button class="btn btn-success" onclick="answerFlashcard(true)">
                            ✅ 我认识
                        </button>
                        <button class="btn btn-primary" onclick="answerFlashcard(false)">
                            🔄 再学一次
                        </button>
                    </div>
                    <button class="btn" onclick="showMainMenu()">
                        🏠 返回菜单
                    </button>
                </div>
            `;
        }

        // 回答闪卡
        function answerFlashcard(correct) {
            if (correct) {
                gameData.score += 5;
                gameData.streak++;
                awardBadgeForStreak();
                awardBadgeForScore();
                if (gameData.streak >= 3) {
                    awardBadge('streak_5');
                }
                if (gameData.score >= 100) {
                    awardBadge('score_100');
                }
                if (gameData.score >= 500) {
                    awardBadge('score_500');
                }
            } else {
                gameData.streak = 0;
            }

            gameData.level++;
            updateStats();
            showFlashcardGame();
        }

        // 配对游戏
        function showMatchingGame() {
            const words = contentLibrary.words[gameData.currentTheme];
            const selectedWords = [...words].sort(() => Math.random() - 0.5).slice(0, 4);
            const pairs = [];
            selectedWords.forEach(word => {
                pairs.push({ type: 'english', value: word.en, match: word.zh, emoji: word.emoji });
                pairs.push({ type: 'chinese', value: word.zh, match: word.en, emoji: word.emoji });
            });
            const shuffledPairs = [...pairs].sort(() => Math.random() - 0.5);

            const content = document.getElementById('gameContent');
            content.innerHTML = `
                <div class="game-info">
                    <div class="info-title">🧩 配对游戏</div>
                    <div class="info-content">
                        点击卡片，将英文和中文配对
                    </div>
                </div>
                <div class="matching-grid" id="matchingGrid">
                    ${shuffledPairs.map((pair, index) => `
                        <div class="matching-card" onclick="selectMatchingCard(${index})" data-index="${index}">
                            <div class="matching-emoji">${pair.emoji}</div>
                            <div>${pair.value}</div>
                        </div>
                    `).join('')}
                </div>
                <div class="btn-group">
                    <button class="btn" onclick="showMainMenu()">
                        🏠 返回菜单
                    </button>
                </div>
            `;

            window.matchingPairs = shuffledPairs;
            window.selectedMatchingCards = [];
            window.matchedCount = 0;
        }

        // 选择配对卡片
        function selectMatchingCard(index) {
            const card = document.querySelector(`[data-index="${index}"]`);
            if (card.classList.contains('matched') || card.classList.contains('selected')) return;

            card.classList.add('selected');
            window.selectedMatchingCards.push(index);

            if (window.selectedMatchingCards.length === 2) {
                const [idx1, idx2] = window.selectedMatchingCards;
                const pair1 = window.matchingPairs[idx1];
                const pair2 = window.matchingPairs[idx2];

                if ((pair1.type === 'english' && pair2.type === 'chinese' && pair1.match === pair2.value) ||
                    (pair2.type === 'english' && pair1.type === 'chinese' && pair2.match === pair1.value)) {
                    // 匹配成功
                    document.querySelector(`[data-index="${idx1}"]`).classList.remove('selected');
                    document.querySelector(`[data-index="${idx2}"]`).classList.remove('selected');
                    document.querySelector(`[data-index="${idx1}"]`).classList.add('matched');
                    document.querySelector(`[data-index="${idx2}"]`).classList.add('matched');
                    gameData.score += 10;
                    gameData.streak++;
                    window.matchedCount++;
                    awardBadgeForStreak();
                    awardBadgeForScore();
                    updateStats();
                    awardBadge('matching_champ');

                    // 检查是否全部匹配
                    if (window.matchedCount === 4) {
                        setTimeout(() => {
                            alert('🎉 太棒了！所有配对都完成了！');
                            gameData.level++;
                            showMatchingGame();
                        }, 500);
                    }
                } else {
                    // 匹配失败
                    setTimeout(() => {
                        document.querySelector(`[data-index="${idx1}"]`).classList.remove('selected');
                        document.querySelector(`[data-index="${idx2}"]`).classList.remove('selected');
                        gameData.streak = 0;
                        updateStats();
                    }, 1000);
                }

                window.selectedMatchingCards = [];
            }
        }

        // 拼写游戏
        function showSpellingGame() {
            const word = getRandomWord();
            const letters = word.en.split('');
            const scrambled = [...letters].sort(() => Math.random() - 0.5);

            const content = document.getElementById('gameContent');
            content.innerHTML = `
                <div class="game-info">
                    <div class="info-title">✍️ 拼写练习</div>
                    <div class="info-content">
                        根据意思点击字母拼写出单词
                    </div>
                </div>
                <div class="spelling-area">
                    <div class="spelling-hint">
                        拼出单词：<strong>${word.zh}</strong>
                        <div class="spelling-emoji">${word.emoji}</div>
                    </div>
                    <div class="current-spelling" id="currentSpelling"></div>
                    <div class="letter-bank" id="letterBank">
                        ${scrambled.map((letter, idx) => `
                            <div class="letter-tile" onclick="selectSpellingLetter(${idx})" data-letter="${letter}">
                                ${letter}
                            </div>
                        `).join('')}
                    </div>
                </div>
                <div class="btn-group">
                    <div class="btn-row">
                        <button class="btn btn-success" onclick="checkSpelling()">
                            ✅ 检查
                        </button>
                        <button class="btn btn-warning" onclick="resetSpelling()">
                            🔄 重来
                        </button>
                    </div>
                    <button class="btn" onclick="showMainMenu()">
                        🏠 返回菜单
                    </button>
                </div>
            `;

            window.currentWord = word.en;
            window.selectedLetters = [];
            window.originalLetters = scrambled;
            updateSpellingDisplay();
        }

        // 选择拼写字母
        function selectSpellingLetter(index) {
            const tile = document.querySelectorAll('.letter-tile')[index];
            const letter = tile.dataset.letter;

            if (tile.classList.contains('used')) {
                return;
            }

            tile.classList.add('used');
            window.selectedLetters.push(letter);
            updateSpellingDisplay();
        }

        // 重置拼写
        function resetSpelling() {
            window.selectedLetters = [];
            const tiles = document.querySelectorAll('.letter-tile');
            tiles.forEach(tile => tile.classList.remove('used'));
            updateSpellingDisplay();
        }

        // 更新拼写显示
        function updateSpellingDisplay() {
            const display = document.getElementById('currentSpelling');
            if (window.selectedLetters.length === 0) {
                display.textContent = '请点击字母开始拼写';
            } else {
                display.textContent = window.selectedLetters.join(' ');
            }
        }

        // 检查拼写
        function checkSpelling() {
            const userSpelling = window.selectedLetters.join('');
            if (userSpelling.toUpperCase() === window.currentWord.toUpperCase()) {
                alert('🎉 拼写正确！太棒了！');
                gameData.score += 10;
                gameData.streak++;
                awardBadge('spelling_master');
                awardBadgeForStreak();
                awardBadgeForScore();
                gameData.level++;
                updateStats();
                showSpellingGame();
            } else {
                alert(`❌ 不对哦，正确答案是：${window.currentWord}\n再试一次吧！💪`);
                gameData.streak = 0;
                updateStats();
                resetSpelling();
            }
        }

        // 听力游戏
        function showListeningGame() {
            const words = contentLibrary.words[gameData.currentTheme];
            const selectedWords = [...words].sort(() => Math.random() - 0.5).slice(0, 4);
            const targetWord = selectedWords[Math.floor(Math.random() * selectedWords.length)];

            const content = document.getElementById('gameContent');
            content.innerHTML = `
                <div class="game-info">
                    <div class="info-title">🎧 听力测试</div>
                    <div class="info-content">
                        点击播放按钮听单词，然后选择正确答案<br>
                        💡 提示：本版本为演示，实际可接入语音合成
                    </div>
                </div>
                <div class="listening-area">
                    <button class="play-btn" onclick="playAudio()">
                        🔊
                    </button>
                    <p style="color:#666;">请听这个单词：${targetWord.zh}（${targetWord.emoji}）</p>
                </div>
                <div class="listening-options">
                    ${selectedWords.map(word => `
                        <div class="listening-option" onclick="checkListeningAnswer('${word.en}', '${targetWord.en}')">
                            ${word.emoji}<br>${word.en}
                        </div>
                    `).join('')}
                </div>
                <div class="btn-group">
                    <button class="btn" onclick="showMainMenu()">
                        🏠 返回菜单
                    </button>
                </div>
            `;
        }

        // 播放音频（模拟）
        function playAudio() {
            alert('🔊 汪汪！\n这是模拟播放演示\n实际使用可接入专业英语语音合成');
        }

        // 检查听力答案
        function checkListeningAnswer(userAnswer, correctAnswer) {
            if (userAnswer === correctAnswer) {
                alert('🎉 答对了！太棒了！');
                gameData.score += 10;
                gameData.streak++;
                awardBadgeForStreak();
                awardBadgeForScore();
                gameData.level++;
                updateStats();
                showListeningGame();
            } else {
                alert('❌ 不对哦，再听一次试试！💪');
                gameData.streak = 0;
                updateStats();
            }
        }

        // 显示徽章
        function showBadges() {
            const content = document.getElementById('gameContent');
            content.innerHTML = `
                <div class="game-info">
                    <div class="info-title">🏆 徽章收藏</div>
                    <div class="info-content">
                        完成挑战收集徽章！你已获得 ${gameData.earnedBadges.length} / ${badgesList.length} 个徽章
                    </div>
                </div>
                <div class="badges-grid">
                    ${badgesList.map(badge => `
                        <div class="badge-item">
                            <div class="badge-circle ${gameData.earnedBadges.includes(badge.id) ? 'earned' : ''}" 
                                 title="${badge.name}">
                                ${badge.icon}
                            </div>
                            <div class="badge-name">${badge.name}</div>
                        </div>
                    `).join('')}
                </div>
                <div class="btn-group">
                    <button class="btn" onclick="showMainMenu()">
                        🏠 返回菜单
                    </button>
                </div>
            `;
        }

        // 颁发徽章
        function awardBadge(badgeId) {
            if (!gameData.earnedBadges.includes(badgeId)) {
                gameData.earnedBadges.push(badgeId);
                checkVocabBadge();
                updateStats();
            }
        }

        // 根据连胜颁发徽章
        function awardBadgeForStreak() {
            if (gameData.streak >= 5) awardBadge('streak_5');
            if (gameData.streak >= 10) awardBadge('streak_10');
        }

        // 根据分数颁发徽章
        function awardBadgeForScore() {
            if (gameData.score >= 100) awardBadge('score_100');
            if (gameData.score >= 500) awardBadge('score_500');
        }

        // 检查主题徽章
        function checkThemeBadges() {
            switch(gameData.currentTheme) {
                case 'animals':
                    if (gameData.score > 50) awardBadge('animals_expert');
                    break;
                case 'fruits':
                    if (gameData.score > 50) awardBadge('fruits_expert');
                    break;
                case 'colors':
                    if (gameData.score > 50) awardBadge('colors_expert');
                    break;
            }
        }

        // 检查所有主题徽章
        function checkAllThemesBadge() {
            const earnedThemes = [];
            if (gameData.earnedBadges.includes('animals_expert')) earnedThemes.push('animals_expert');
            if (gameData.earnedBadges.includes('fruits_expert')) earnedThemes.push('fruits_expert');
            if (gameData.earnedBadges.includes('colors_expert')) earnedThemes.push('colors_expert');

            if (earnedThemes.length >= 3) {
                awardBadge('all_themes');
            }
        }

        // 检查词汇达人徽章
        function checkVocabBadge() {
            if (gameData.score >= 200) {
                awardBadge('vocab_master');
            }
        }

        // 更新统计信息
        function updateStats() {
            document.getElementById('scoreDisplay').textContent = gameData.score;
            document.getElementById('streakDisplay').textContent = gameData.streak;
            document.getElementById('badgeCount').textContent = gameData.earnedBadges.length;
        }

        // 页面加载完成后初始化
        window.onload = initGame;
    </script>
</body>
</html>
