            .badge-circle { width: 60px; height: 60px; font-size: 28px; }
        }

        @media (max-width: 320px) {
            .game-modes { grid-template-columns: 1fr; }
            .matching-grid { grid-template-columns: 1fr; }
            .audio-controls { flex-direction: column; }
            .audio-btn { width: 100%; }
            .badges-grid { grid-template-columns: repeat(2, 1fr); }
        }
    </style>
</head>
<body>
    <!-- 雪花背景 -->
    <div class="snowflakes" id="snowflakes"></div>

    <div class="container">
        <!-- 冰雪奇缘头部 -->
        <div class="header">
            <h1>❄️ 冰雪奇缘英语乐园 🔊</h1>
            <p>点击单词听发音，快乐学英语！</p>
        </div>

        <!-- 音频控制栏 -->
        <div class="audio-controls">
            <button class="audio-btn" id="autoPlayBtn">
                <span>🔊</span> 自动播放
            </button>
            <button class="audio-btn" id="repeatBtn">
                <span>🔁</span> 重复播放
            </button>
            <button class="audio-btn" id="muteBtn">
                <span>🔈</span> 静音
            </button>
        </div>

        <!-- 主内容区 -->
        <div class="content" id="content">
            <!-- 欢迎界面 -->
            <div class="welcome-card" id="welcomeCard">
                <div class="welcome-emoji">👑❄️✨</div>
                <div class="welcome-title">欢迎来到冰雪奇缘英语乐园！</div>
                <div class="welcome-text">
                    这里有102个英语单词，8大主题，12个冰雪徽章！<br>
                    <strong>点击单词可以听发音</strong>，跟着艾莎安娜一起快乐学英语！
                </div>
                <div class="word-count">🎯 102个单词 | 8大主题 | 12个徽章</div>
                <div class="audio-play-controls" style="margin-top: 25px;">
                    <button class="play-btn play-english" onclick="speakEnglish('Welcome to Frozen English World!')">
                        <span>🔊</span> 试听英语
                    </button>
                    <button class="play-btn play-chinese" onclick="speakChinese('欢迎来到冰雪奇缘英语乐园！')">
                        <span>🔊</span> 试听中文
                    </button>
                </div>
            </div>

            <!-- 游戏模式选择 -->
            <div class="game-modes" id="gameModes" style="display: none;">
                <div class="mode-card active" onclick="selectMode('flashcard')">
                    <div class="mode-icon">📖</div>
                    <div class="mode-name">闪卡学习</div>
                    <div class="mode-desc">点击单词听发音</div>
                </div>
                <div class="mode-card" onclick="selectMode('matching')">
                    <div class="mode-icon">🧩</div>
                    <div class="mode-name">配对游戏</div>
                    <div class="mode-desc">听声音找对应</div>
                </div>
                <div class="mode-card" onclick="selectMode('spelling')">
                    <div class="mode-icon">✍️</div>
                    <div class="mode-name">拼写练习</div>
                    <div class="mode-desc">听声音拼单词</div>
                </div>
                <div class="mode-card" onclick="selectMode('listening')">
                    <div class="mode-icon">🎧</div>
                    <div class="mode-name">听力测试</div>
                    <div class="mode-desc">听声音选答案</div>
                </div>
            </div>

            <!-- 闪卡模式 -->
            <div class="flashcard" id="flashcard" style="display: none;">
                <div class="flashcard-emoji" id="currentEmoji">🍎</div>
                <div class="flashcard-word" id="currentWord" onclick="playCurrentWord()">apple</div>
                <div class="flashcard-translation" id="currentTranslation" onclick="playCurrentTranslation()">苹果</div>
                <div class="flashcard-hint">点击单词听发音</div>
                <div class="audio-play-controls">
                    <button class="play-btn play-english" onclick="playCurrentWord()">
                        <span>🔊</span> 播放英语
                    </button>
                    <button class="play-btn play-chinese" onclick="playCurrentTranslation()">
                        <span>🔊</span> 播放中文
                    </button>
                </div>
            </div>

            <!-- 配对游戏 -->
            <div class="matching-grid" id="matchingGame" style="display: none;">
                <!-- 动态生成配对卡片 -->
            </div>

            <!-- 拼写游戏 -->
            <div class="spelling-area" id="spellingGame" style="display: none;">
                <div class="spelling-hint">听声音，拼出单词：</div>
                <div class="spelling-emoji" id="spellingEmoji" onclick="playSpellingWord()">🍎</div>
                <div class="current-spelling" id="currentSpelling"></div>
                <div class="letter-bank" id="letterBank"></div>
            </div>

            <!-- 听力游戏 -->
            <div class="listening-area" id="listeningGame" style="display: none;">
                <div class="spelling-hint">听声音，选择正确答案：</div>
                <div class="big-play-btn" id="listenPlayBtn" onclick="playListeningWord()">
                    🔊
                </div>
                <div class="listening-options" id="listeningOptions"></div>
            </div>

            <!-- 徽章展示 -->
            <div class="badges-grid" id="badgesGrid" style="display: none;">
                <!-- 动态生成徽章 -->
            </div>
        </div>

        <!-- 按钮组 -->
        <div class="btn-group" id="btnGroup" style="display: none;">
            <div class="btn-row">
                <button class="btn btn-primary" onclick="nextWord()">下一个 ▶️</button>
                <button class="btn btn-success" onclick="repeatWord()">重复 🔁</button>
            </div>
            <div class="btn-row">
                <button class="btn btn-warning" onclick="showBadges()">查看徽章 👑</button>
                <button class="btn btn-info" onclick="changeTheme()">切换主题 🎨</button>
            </div>
        </div>

        <!-- 统计栏 -->
        <div class="stats-bar">
            <div class="stat-item">
                <div class="stat-value" id="wordCount">0</div>
                <div class="stat-label">已学单词</div>
            </div>
            <div class="stat-item">
                <div class="stat-value" id="correctCount">0</div>
                <div class="stat-label">答对次数</div>
            </div>
            <div class="stat-item">
                <div class="stat-value" id="badgeCount">0</div>
                <div class="stat-label">获得徽章</div>
            </div>
        </div>
    </div>
    <script>
        // ==================== 音频系统核心 ====================
        class AudioSystem {
            constructor() {
                this.speechSynthesis = window.speechSynthesis;
                this.isSpeaking = false;
                this.autoPlay = true;
                this.repeatMode = false;
                this.muted = false;
                this.currentUtterance = null;

                // 支持的语言
                this.languages = {
                    'en-US': '英语 (美国)',
                    'zh-CN': '中文 (普通话)'
                };

                // 声音设置
                this.voiceSettings = {
                    'en-US': {
                        rate: 0.8,  // 语速较慢，适合小朋友
                        pitch: 1.0,
                        volume: 1.0
                    },
                    'zh-CN': {
                        rate: 0.9,
                        pitch: 1.0,
                        volume: 1.0
                    }
                };

                this.init();
            }

            init() {
                // 检查浏览器支持
                if (!('speechSynthesis' in window)) {
                    this.showAudioError('您的浏览器不支持语音合成功能，请使用Chrome、Safari或Edge浏览器');
                    return false;
                }

                // 等待语音引擎加载
                setTimeout(() => {
                    const voices = this.speechSynthesis.getVoices();
                    if (voices.length === 0) {
                        console.log('语音引擎正在加载...');
                    }
                }, 100);

                return true;
            }

            // 播放英语
            speakEnglish(text) {
                if (this.muted) return;
                this.speak(text, 'en-US');
            }

            // 播放中文
            speakChinese(text) {
                if (this.muted) return;
                this.speak(text, 'zh-CN');
            }

            // 核心播放函数
            speak(text, lang = 'en-US') {
                if (this.isSpeaking) {
                    this.speechSynthesis.cancel();
                }

                const utterance = new SpeechSynthesisUtterance(text);
                utterance.lang = lang;

                // 应用声音设置
                const settings = this.voiceSettings[lang] || this.voiceSettings['en-US'];
                utterance.rate = settings.rate;
                utterance.pitch = settings.pitch;
                utterance.volume = settings.volume;

                // 选择最佳语音
                const voices = this.speechSynthesis.getVoices();
                const targetVoice = voices.find(voice => 
                    voice.lang === lang && 
                    voice.name.includes('Female')
                ) || voices.find(voice => voice.lang === lang) || voices[0];

                if (targetVoice) {
                    utterance.voice = targetVoice;
                }

                // 事件监听
                utterance.onstart = () => {
                    this.isSpeaking = true;
                    this.currentUtterance = utterance;
                    this.onSpeechStart(text, lang);
                };

                utterance.onend = () => {
                    this.isSpeaking = false;
                    this.currentUtterance = null;
                    this.onSpeechEnd(text, lang);

                    // 重复播放模式
                    if (this.repeatMode) {
                        setTimeout(() => this.speak(text, lang), 1000);
                    }
                };

                utterance.onerror = (event) => {
                    this.isSpeaking = false;
                    this.currentUtterance = null;
                    console.error('语音播放错误:', event.error);
                    this.onSpeechError(text, lang);
                };

                // 开始播放
                this.speechSynthesis.speak(utterance);
            }

            // 停止当前播放
            stop() {
                if (this.isSpeaking) {
                    this.speechSynthesis.cancel();
                    this.isSpeaking = false;
                    this.currentUtterance = null;
                }
            }

            // 切换自动播放
            toggleAutoPlay() {
                this.autoPlay = !this.autoPlay;
                return this.autoPlay;
            }

            // 切换重复播放
            toggleRepeat() {
                this.repeatMode = !this.repeatMode;
                return this.repeatMode;
            }

            // 切换静音
            toggleMute() {
                this.muted = !this.muted;
                if (this.muted && this.isSpeaking) {
                    this.stop();
                }
                return this.muted;
            }

            // 事件回调
            onSpeechStart(text, lang) {
                console.log(`开始播放: ${text} (${lang})`);
                // 添加播放动画
                const playingElement = document.querySelector('.playing');
                if (playingElement) {
                    playingElement.classList.remove('playing');
                }

                // 根据语言找到对应的元素
                if (lang === 'en-US') {
                    const wordElement = document.getElementById('currentWord');
                    if (wordElement && wordElement.textContent === text) {
                        wordElement.classList.add('playing');
                    }
                } else if (lang === 'zh-CN') {
                    const transElement = document.getElementById('currentTranslation');
                    if (transElement && transElement.textContent === text) {
                        transElement.classList.add('playing');
                    }
                }
            }

            onSpeechEnd(text, lang) {
                console.log(`播放结束: ${text} (${lang})`);
                // 移除播放动画
                const playingElements = document.querySelectorAll('.playing');
                playingElements.forEach(el => el.classList.remove('playing'));
            }

            onSpeechError(text, lang) {
                console.error(`播放失败: ${text} (${lang})`);
                // 可以在这里添加错误提示
            }

            showAudioError(message) {
                alert(message);
            }
        }

        // ==================== 游戏数据 ====================
        const gameData = {
            themes: [
                {
                    id: 'animals',
                    name: '动物世界',
                    emoji: '🐾',
                    words: [
                        { word: 'cat', chinese: '猫', emoji: '🐱' },
                        { word: 'dog', chinese: '狗', emoji: '🐶' },
                        { word: 'bird', chinese: '鸟', emoji: '🐦' },
                        { word: 'fish', chinese: '鱼', emoji: '🐟' },
                        { word: 'rabbit', chinese: '兔子', emoji: '🐰' },
                        { word: 'bear', chinese: '熊', emoji: '🐻' },
                        { word: 'lion', chinese: '狮子', emoji: '🦁' },
