            if (answered) return;
            answered = true;

            if (selected === correct) {
                optionElement.classList.add('correct');
                score++;
                updateScore();
                setTimeout(() => {
                    currentQuestionIndex++;
                    updateProgress();
                    showQuestion();
                }, 800);
            } else {
