        }
        .speaker-btn:active {
            transform: scale(0.95);
        }
        .options-grid {
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: 15px;
        }
        .option-card {
            background: #F5F9FF;
            border: 3px solid #E3F2FD;
            border-radius: 15px;
            padding: 15px;
            cursor: pointer;
            transition: all 0.3s ease;
            text-align: center;
            min-height: 80px;
            display: flex;
            align-items: center;
            justify-content: center;
        }
        .option-card:hover {
            border-color: var(--paw-light-blue);
            background: #E3F2FD;
            transform: scale(1.03);
        }
        .option-card.correct {
            border-color: var(--paw-green);
            background: #E8F5E9;
            animation: correctPulse 0.6s ease;
        }
        .option-card.wrong {
            border-color: var(--paw-red);
            background: #FFEBEE;
            animation: wrongShake 0.5s ease;
        }
        .option-text {
            font-family: 'Fredoka', sans-serif;
            font-size: 1.3rem;
            color: var(--text-dark);
        }
        /* Result Section */
        .result-section {
            display: none;
            animation: fadeIn 0.5s ease-out;
        }
        .result-section.active {
            display: block;
        }
        .result-card {
            background: var(--card-bg);
            border-radius: 25px;
            padding: 40px 30px;
            text-align: center;
            box-shadow: var(--shadow);
        }
        .trophy {
            font-size: 6rem;
            animation: bounce 1s ease infinite;
            margin-bottom: 20px;
        }
        .result-title {
            font-family: 'Fredoka', sans-serif;
            font-size: 2.5rem;
            color: var(--paw-blue);
            margin-bottom: 15px;
        }
        .result-score {
            font-size: 1.5rem;
            color: var(--text-medium);
            margin-bottom: 30px;
        }
        .result-score span {
            font-family: 'Fredoka', sans-serif;
            font-size: 3rem;
            color: var(--paw-yellow);
            text-shadow: 2px 2px 0 var(--paw-blue);
        }
        .buttons-row {
            display: flex;
            gap: 20px;
            justify-content: center;
            flex-wrap: wrap;
        }
        .btn-secondary {
            background: linear-gradient(135deg, var(--paw-yellow), #FFE040);
            color: var(--paw-blue);
        }
        /* Progress Bar */
        .progress-container {
            width: 100%;
            height: 12px;
            background: #E3F2FD;
            border-radius: 6px;
            margin: 20px 0;
            overflow: hidden;
        }
        .progress-bar {
            height: 100%;
            background: linear-gradient(90deg, var(--paw-yellow), var(--paw-green));
            border-radius: 6px;
            transition: width 0.5s ease;
        }
        .progress-text {
            text-align: center;
            font-size: 0.9rem;
            color: var(--text-medium);
            margin-bottom: 5px;
        }
        /* Animations */
        @keyframes slideDown {
            from {
                opacity: 0;
                transform: translateY(-20px);
            }
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }
        @keyframes bounceIn {
            0% {
                opacity: 0;
                transform: scale(0.3);
            }
            50% {
                opacity: 1;
                transform: scale(1.05);
            }
            100% {
                transform: scale(1);
            }
        }
        @keyframes fadeIn {
            from {
                opacity: 0;
            }
            to {
                opacity: 1;
            }
        }
        @keyframes correctPulse {
            0% { transform: scale(1); }
            50% { transform: scale(1.05); }
            100% { transform: scale(1); }
        }
        @keyframes wrongShake {
            0%, 100% { transform: translateX(0); }
            25% { transform: translateX(-8px); }
            75% { transform: translateX(8px); }
        }
        @keyframes bounce {
            0%, 100% { transform: translateY(0); }
            50% { transform: translateY(-15px); }
        }
        /* Responsive */
        @media (max-width: 768px) {
            .logo {
                font-size: 2rem;
            }
            .section-title {
                font-size: 1.5rem;
            }
            .characters-grid {
                grid-template-columns: repeat(2, 1fr);
                gap: 15px;
            }
            .options-grid {
                grid-template-columns: 1fr;
            }
            .game-area {
                padding: 20px 15px;
            }
            .question-text {
                font-size: 1.5rem;
            }
            .buttons-row {
                flex-direction: column;
                align-items: center;
            }
            .btn {
                max-width: 250px;
            }
            .character-avatar {
                width: 100px;
                height: 100px;
            }
        }
        @media (max-width: 480px) {
            .characters-grid {
                grid-template-columns: 1fr;
            }
            .container {
                padding: 15px;
            }
        }
        /* Confetti */
        .confetti {
            position: fixed;
            width: 10px;
            height: 10px;
            opacity: 0;
            animation: confetti-fall 3s ease-in forwards;
        }
        @keyframes confetti-fall {
            0% {
                opacity: 1;
                transform: translateY(-10px) rotate(0deg);
            }
            100% {
                opacity: 1;
                transform: translateY(100vh) rotate(360deg);
            }
        }
        /* Loading */
        .loading {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: var(--bg-gradient);
            display: flex;
            align-items: center;
            justify-content: center;
            z-index: 1000;
            transition: opacity 0.5s ease;
        }
        .loading.hidden {
            opacity: 0;
            pointer-events: none;
        }
        .loading-spinner {
            width: 60px;
            height: 60px;
            border: 5px solid rgba(255, 255, 255, 0.3);
            border-radius: 50%;
            border-top-color: var(--paw-blue);
            animation: spin 1s ease-in-out infinite;
        }
        @keyframes spin {
            to { transform: rotate(360deg); }
        }
