            font-weight: 800;
            color: var(--paw-blue);
            text-align: center;
            margin-bottom: 15px;
            letter-spacing: 8px;
            text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.1);
        }
        .question-hint {
            font-family: 'Nunito', sans-serif;
            font-size: 1.3rem;
            color: var(--text-medium);
            text-align: center;
            margin-bottom: 25px;
        }
        .word-audio {
            text-align: center;
            margin-bottom: 25px;
        }
        .speaker-btn {
            width: 70px;
            height: 70px;
            border-radius: 50%;
            border: none;
            background: linear-gradient(135deg, var(--paw-yellow), #FFE040);
            cursor: pointer;
            box-shadow: 0 4px 12px rgba(255, 209, 0, 0.4);
            transition: all 0.3s ease;
            font-size: 2rem;
        }
        .speaker-btn:hover {
            transform: scale(1.1);
            box-shadow: 0 6px 16px rgba(255, 209, 0, 0.5);
        }
        .speaker-btn:active {
            transform: scale(0.95);
        }
        .options-grid {
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: 15px;
        }
        .option-card {
            background: #F5F9FF;
            border: 3px solid #E3F2FD;
            border-radius: 15px;
            padding: 20px 15px;
            cursor: pointer;
            transition: all 0.3s ease;
            text-align: center;
            min-height: 90px;
            display: flex;
            align-items: center;
            justify-content: center;
        }
        .option-card:hover {
            border-color: var(--paw-light-blue);
            background: #E3F2FD;
            transform: scale(1.03);
        }
        .option-card.correct {
            border-color: var(--paw-green);
            background: #E8F5E9;
            animation: correctPulse 0.6s ease;
        }
        .option-card.wrong {
            border-color: var(--paw-red);
            background: #FFEBEE;
            animation: wrongShake 0.5s ease;
        }
        .option-text {
            font-family: 'Open Sans', sans-serif;
            font-size: 1.6rem;
            font-weight: 700;
            color: var(--text-dark);
        }
        /* Result Section */
        .result-section {
            display: none;
            animation: fadeIn 0.5s ease-out;
        }
        .result-section.active {
            display: block;
        }
        .result-card {
            background: var(--card-bg);
            border-radius: 25px;
            padding: 40px 30px;
            text-align: center;
            box-shadow: var(--shadow);
        }
        .trophy {
            font-size: 6rem;
            animation: bounce 1s ease infinite;
            margin-bottom: 20px;
        }
        .result-title {
            font-family: 'Fredoka', sans-serif;
            font-size: 2.5rem;
            color: var(--paw-blue);
            margin-bottom: 15px;
