        .progress-container {
            width: 100%;
            height: 12px;
            background: #E3F2FD;
            border-radius: 6px;
            margin: 20px 0;
            overflow: hidden;
        }
        .progress-bar {
            height: 100%;
            background: linear-gradient(90deg, var(--paw-yellow), var(--paw-green));
            border-radius: 6px;
            transition: width 0.5s ease;
        }
        .progress-text {
            text-align: center;
            font-size: 0.9rem;
            color: var(--text-medium);
            margin-bottom: 5px;
        }
        /* Animations */
        @keyframes slideDown {
            from {
                opacity: 0;
                transform: translateY(-20px);
            }
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }
        @keyframes bounceIn {
            0% {
                opacity: 0;
                transform: scale(0.3);
            }
            50% {
                opacity: 1;
                transform: scale(1.05);
            }
            100% {
                transform: scale(1);
            }
        }
        @keyframes fadeIn {
            from {
                opacity: 0;
            }
            to {
                opacity: 1;
            }
        }
        @keyframes correctPulse {
            0% { transform: scale(1); }
            50% { transform: scale(1.05); }
            100% { transform: scale(1); }
        }
        @keyframes wrongShake {
            0%, 100% { transform: translateX(0); }
            25% { transform: translateX(-8px); }
            75% { transform: translateX(8px); }
        }
        @keyframes bounce {
            0%, 100% { transform: translateY(0); }
            50% { transform: translateY(-15px); }
        }
        /* Responsive */
        @media (max-width: 768px) {
            .logo {
                font-size: 2rem;
            }
            .section-title {
                font-size: 1.5rem;
            }
            .characters-grid {
                grid-template-columns: repeat(2, 1fr);
                gap: 15px;
            }
            .options-grid {
                grid-template-columns: 1fr;
            }
            .game-area {
                padding: 20px 15px;
            }
            .question-text {
                font-size: 2.8rem;
                letter-spacing: 6px;
            }
            .question-hint {
                font-size: 1.1rem;
            }
            .buttons-row {
                flex-direction: column;
                align-items: center;
            }
            .btn {
                max-width: 250px;
            }
            .character-avatar {
                width: 100px;
                height: 100px;
            }
            .option-text {
                font-size: 1.4rem;
            }
        }
        @media (max-width: 480px) {
            .characters-grid {
                grid-template-columns: 1fr;
            }
            .container {
                padding: 15px;
            }
            .question-text {
                font-size: 2.2rem;
                letter-spacing: 4px;
            }
        }
