            margin-bottom: 5px;
        }
        /* Animations */
        @keyframes slideDown {
            from {
                opacity: 0;
                transform: translateY(-20px);
            }
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }
        @keyframes bounceIn {
            0% {
                opacity: 0;
                transform: scale(0.3);
            }
            50% {
                opacity: 1;
                transform: scale(1.05);
            }
            100% {
                transform: scale(1);
            }
        }
        @keyframes fadeIn {
            from {
                opacity: 0;
            }
            to {
                opacity: 1;
            }
        }
        @keyframes correctPulse {
            0% { transform: scale(1); }
            50% { transform: scale(1.05); }
            100% { transform: scale(1); }
        }
        @keyframes wrongShake {
            0%, 100% { transform: translateX(0); }
            25% { transform: translateX(-8px); }
            75% { transform: translateX(8px); }
        }
        @keyframes bounce {
            0%, 100% { transform: translateY(0); }
            50% { transform: translateY(-15px); }
        }
        /* Responsive */
        @media (max-width: 768px) {
            .logo {
                font-size: 2rem;
            }
            .section-title {
                font-size: 1.5rem;
            }
            .characters-grid {
                grid-template-columns: repeat(2, 1fr);
                gap: 15px;
            }
            .options-grid {
                grid-template-columns: 1fr;
            }
            .game-area {
                padding: 20px 15px;
            }
            .question-text {
                font-size: 2.8rem;
                letter-spacing: 6px;
            }
            .question-hint {
                font-size: 1.1rem;
            }
            .buttons-row {
                flex-direction: column;
                align-items: center;
            }
            .btn {
                max-width: 250px;
            }
            .character-avatar {
                width: 100px;
                height: 100px;
            }
            .option-text {
                font-size: 1.4rem;
            }
        }
        @media (max-width: 480px) {
            .characters-grid {
                grid-template-columns: 1fr;
            }
            .container {
                padding: 15px;
            }
            .question-text {
                font-size: 2.2rem;
                letter-spacing: 4px;
            }
        }
        /* Confetti */
        .confetti {
            position: fixed;
            width: 10px;
            height: 10px;
            opacity: 0;
            animation: confetti-fall 3s ease-in forwards;
        }
        @keyframes confetti-fall {
            0% {
                opacity: 1;
                transform: translateY(-10px) rotate(0deg);
            }
            100% {
                opacity: 1;
                transform: translateY(100vh) rotate(360deg);
            }
        }
        /* Loading */
        .loading {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: var(--bg-gradient);
            display: flex;
            align-items: center;
            justify-content: center;
            z-index: 1000;
            transition: opacity 0.5s ease;
        }
        .loading.hidden {
            opacity: 0;
            pointer-events: none;
        }
        .loading-spinner {
            width: 60px;
            height: 60px;
            border: 5px solid rgba(255, 255, 255, 0.3);
            border-radius: 50%;
            border-top-color: var(--paw-blue);
            animation: spin 1s ease-in-out infinite;
        }
        @keyframes spin {
            to { transform: rotate(360deg); }
        }
