        .btn:hover {
            transform: translateY(-3px) scale(1.05);
            box-shadow: var(--shadow-hover);
            background: linear-gradient(135deg, var(--paw-light-blue), var(--paw-blue));
        }
        .btn:active {
            transform: translateY(0) scale(0.98);
        }
        .btn:disabled {
            opacity: 0.5;
            cursor: not-allowed;
            transform: none;
        }
        .btn-back {
            background: linear-gradient(135deg, #9E9E9E, #BDBDBD);
            margin-top: 15px;
        }
        /* Game Section */
        .game-section {
            display: none;
            animation: fadeIn 0.5s ease-out;
        }
        .game-section.active {
            display: block;
        }
        .game-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            background: var(--card-bg);
            padding: 15px 25px;
            border-radius: 15px;
            margin-bottom: 25px;
            box-shadow: var(--shadow);
        }
        .score-box {
            text-align: center;
        }
        .score-label {
            font-size: 0.9rem;
            color: var(--text-medium);
            font-weight: 600;
        }
        .score-value {
            font-family: 'Fredoka', sans-serif;
            font-size: 2rem;
            color: var(--paw-yellow);
            text-shadow: 1px 1px 0 var(--paw-blue);
        }
        .current-character {
            display: flex;
            align-items: center;
            gap: 10px;
        }
        .character-badge {
            width: 50px;
            height: 50px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 1.5rem;
            background-size: cover;
            background-position: center;
            border: 3px solid white;
            box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
        }
        /* Game Area */
        .game-area {
            background: var(--card-bg);
            border-radius: 20px;
            padding: 30px;
            box-shadow: var(--shadow);
            margin-bottom: 25px;
            position: relative;
        }
        .question-text {
            font-family: 'Open Sans', sans-serif;
            font-size: 4rem;
            font-weight: 800;
            color: var(--paw-blue);
            text-align: center;
            margin-bottom: 15px;
            letter-spacing: 8px;
            text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.1);
        }
        .question-hint {
            font-family: 'Nunito', sans-serif;
            font-size: 1.3rem;
            color: var(--text-medium);
            text-align: center;
            margin-bottom: 25px;
        }
        .word-audio {
            text-align: center;
            margin-bottom: 25px;
        }
        .speaker-btn {
            width: 70px;
            height: 70px;
            border-radius: 50%;
            border: none;
            background: linear-gradient(135deg, var(--paw-yellow), #FFE040);
            cursor: pointer;
            box-shadow: 0 4px 12px rgba(255, 209, 0, 0.4);
            transition: all 0.3s ease;
            font-size: 2rem;
        }
        .speaker-btn:hover {
            transform: scale(1.1);
            box-shadow: 0 6px 16px rgba(255, 209, 0, 0.5);
        }
        .speaker-btn:active {
            transform: scale(0.95);
        }
        .options-grid {
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: 15px;
        }
        .option-card {
            background: #F5F9FF;
            border: 3px solid #E3F2FD;
            border-radius: 15px;
            padding: 20px 15px;
            cursor: pointer;
            transition: all 0.3s ease;
            text-align: center;
            min-height: 90px;
            display: flex;
            align-items: center;
            justify-content: center;
        }
        .option-card:hover {
            border-color: var(--paw-light-blue);
            background: #E3F2FD;
            transform: scale(1.03);
        }
        .option-card.correct {
            border-color: var(--paw-green);
            background: #E8F5E9;
            animation: correctPulse 0.6s ease;
        }
        .option-card.wrong {
            border-color: var(--paw-red);
            background: #FFEBEE;
            animation: wrongShake 0.5s ease;
        }
        .option-text {
            font-family: 'Open Sans', sans-serif;
            font-size: 1.6rem;
            font-weight: 700;
            color: var(--text-dark);
        }
        /* Result Section */
        .result-section {
            display: none;
            animation: fadeIn 0.5s ease-out;
        }
        .result-section.active {
            display: block;
        }
        .result-card {
            background: var(--card-bg);
            border-radius: 25px;
            padding: 40px 30px;
            text-align: center;
            box-shadow: var(--shadow);
        }
        .trophy {
            font-size: 6rem;
            animation: bounce 1s ease infinite;
            margin-bottom: 20px;
        }
        .result-title {
            font-family: 'Fredoka', sans-serif;
            font-size: 2.5rem;
            color: var(--paw-blue);
            margin-bottom: 15px;
        }
        .result-score {
            font-size: 1.5rem;
            color: var(--text-medium);
            margin-bottom: 30px;
        }
        .result-score span {
            font-family: 'Fredoka', sans-serif;
            font-size: 3rem;
            color: var(--paw-yellow);
            text-shadow: 2px 2px 0 var(--paw-blue);
        }
        .buttons-row {
            display: flex;
            gap: 20px;
            justify-content: center;
            flex-wrap: wrap;
        }
        .btn-secondary {
            background: linear-gradient(135deg, var(--paw-yellow), #FFE040);
            color: var(--paw-blue);
        }
        /* Progress Bar */
        .progress-container {
            width: 100%;
            height: 12px;
            background: #E3F2FD;
            border-radius: 6px;
            margin: 20px 0;
            overflow: hidden;
        }
        .progress-bar {
            height: 100%;
            background: linear-gradient(90deg, var(--paw-yellow), var(--paw-green));
            border-radius: 6px;
            transition: width 0.5s ease;
        }
        .progress-text {
            text-align: center;
            font-size: 0.9rem;
            color: var(--text-medium);
            margin-bottom: 5px;
        }
        /* Badge Display */
        .badge-display {
            position: fixed;
            top: 20px;
            right: 20px;
            background: var(--card-bg);
            border-radius: 15px;
            padding: 15px;
            box-shadow: var(--shadow);
            z-index: 100;
            display: none;
        }
        .badge-display.show {
            display: block;
            animation: slideInRight 0.5s ease-out;
        }
        .badge-title {
            font-size: 0.9rem;
            color: var(--text-medium);
            margin-bottom: 10px;
            text-align: center;
        }
        .badges-grid {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 8px;
        }
        .badge-item {
            width: 40px;
            height: 40px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 1.5rem;
            background: #E3F2FD;
            opacity: 0.3;
        }
        .badge-item.earned {
            opacity: 1;
            background: linear-gradient(135deg, var(--paw-yellow), #FFE040);
            animation: badgePop 0.5s ease;
        }
        /* Animations */
        @keyframes slideDown {
            from { opacity: 0; transform: translateY(-20px); }
            to { opacity: 1; transform: translateY(0); }
        }
        @keyframes bounceIn {
            0% { opacity: 0; transform: scale(0.3); }
            50% { opacity: 1; transform: scale(1.05); }
            100% { transform: scale(1); }
        }
        @keyframes fadeIn {
            from { opacity: 0; }
            to { opacity: 1; }
        }
        @keyframes slideInRight {
            from { opacity: 0; transform: translateX(100px); }
            to { opacity: 1; transform: translateX(0); }
        }
        @keyframes scaleIn {
            from { opacity: 0; transform: scale(0.8); }
            to { opacity: 1; transform: scale(1); }
        }
        @keyframes correctPulse {
            0% { transform: scale(1); }
            50% { transform: scale(1.05); }
            100% { transform: scale(1); }
        }
        @keyframes wrongShake {
            0%, 100% { transform: translateX(0); }
            25% { transform: translateX(-8px); }
            75% { transform: translateX(8px); }
        }
        @keyframes bounce {
            0%, 100% { transform: translateY(0); }
            50% { transform: translateY(-15px); }
        }
        @keyframes badgePop {
            0% { transform: scale(0); }
            50% { transform: scale(1.2); }
            100% { transform: scale(1); }
        }
        /* Responsive */
        @media (max-width: 768px) {
            .logo { font-size: 2rem; }
            .section-title { font-size: 1.5rem; }
            .characters-grid, .difficulty-grid { grid-template-columns: repeat(2, 1fr); gap: 15px; }
            .options-grid { grid-template-columns: 1fr; }
            .game-area { padding: 20px 15px; }
            .question-text { font-size: 2.8rem; letter-spacing: 6px; }
            .question-hint { font-size: 1.1rem; }
            .buttons-row { flex-direction: column; align-items: center; }
            .btn { max-width: 250px; }
            .character-avatar { width: 100px; height: 100px; }
            .option-text { font-size: 1.4rem; }
            .badge-display { top: 10px; right: 10px; padding: 10px; }
            .badge-item { width: 30px; height: 30px; font-size: 1.2rem; }
            .home-btn, .pause-btn { width: 45px; height: 45px; font-size: 1.3rem; }
            .pause-btn { left: 70px; }
        }
        @media (max-width: 480px) {
            .characters-grid, .difficulty-grid { grid-template-columns: 1fr; }
            .container { padding: 15px; }
            .question-text { font-size: 2.2rem; letter-spacing: 4px; }
            .home-btn, .pause-btn { width: 40px; height: 40px; font-size: 1.2rem; }
            .pause-btn { left: 65px; }
        }
        /* Confetti */
        .confetti {
            position: fixed;
            width: 10px;
            height: 10px;
            opacity: 0;
            animation: confetti-fall 3s ease-in forwards;
        }
        @keyframes confetti-fall {
            0% { opacity: 1; transform: translateY(-10px) rotate(0deg); }
            100% { opacity: 1; transform: translateY(100vh) rotate(360deg); }
        }
        /* Loading */
        .loading {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: var(--bg-gradient);
            display: flex;
            align-items: center;
            justify-content: center;
            z-index: 1000;
            transition: opacity 0.5s ease;
        }
        .loading.hidden {
            opacity: 0;
            pointer-events: none;
        }
        .loading-spinner {
            width: 60px;
            height: 60px;
            border: 5px solid rgba(255, 255, 255, 0.3);
            border-radius: 50%;
            border-top-color: var(--paw-blue);
            animation: spin 1s ease-in-out infinite;
        }
        @keyframes spin {
            to { transform: rotate(360deg); }
        }
    </style>
</head>
<body>
