            awardBadge('first_game');
            checkAllThemesBadge();

            switch(mode) {
                case 'flashcard':
                    showFlashcardGame();
                    break;
                case 'matching':
                    showMatchingGame();
                    break;
                case 'spelling':
                    showSpellingGame();
                    break;
                case 'listening':
                    showListeningGame();
