            animation: pulse 1s infinite;
            box-shadow: 0 0 30px rgba(255, 215, 0, 0.6);
        }

        .big-play-btn:active {
            transform: scale(0.95);
        }

        /* 冰雪徽章展示 */
        .badges-grid {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 20px;
            margin: 25px 0;
        }

