        }

        .badge-circle.earned {
            opacity: 1;
            animation: badgePop 0.5s ease;
            box-shadow: 0 0 25px rgba(138, 198, 232, 0.5);
        }

        /* 动画 */
        @keyframes bounce {
            0%, 100% { transform: translateY(0); }
            50% { transform: translateY(-15px); }
        }

        @keyframes pulse {
            0%, 100% { transform: scale(1); }
            50% { transform: scale(1.05); }
