    <script>
        // ==================== 音频系统核心 ====================
        class AudioSystem {
            constructor() {
                this.speechSynthesis = window.speechSynthesis;
                this.isSpeaking = false;
                this.autoPlay = true;
                this.repeatMode = false;
                this.muted = false;
                this.currentUtterance = null;

                // 支持的语言
                this.languages = {
                    'en-US': '英语 (美国)',
                    'zh-CN': '中文 (普通话)'
                };

                // 声音设置
                this.voiceSettings = {
                    'en-US': {
                        rate: 0.8,  // 语速较慢，适合小朋友
                        pitch: 1.0,
                        volume: 1.0
                    },
                    'zh-CN': {
                        rate: 0.9,
                        pitch: 1.0,
                        volume: 1.0
                    }
                };

                this.init();
            }

            init() {
                // 检查浏览器支持
                if (!('speechSynthesis' in window)) {
                    this.showAudioError('您的浏览器不支持语音合成功能，请使用Chrome、Safari或Edge浏览器');
                    return false;
                }

                // 等待语音引擎加载
                setTimeout(() => {
                    const voices = this.speechSynthesis.getVoices();
                    if (voices.length === 0) {
                        console.log('语音引擎正在加载...');
                    }
                }, 100);

                return true;
            }

            // 播放英语
            speakEnglish(text) {
                if (this.muted) return;
                this.speak(text, 'en-US');
            }

            // 播放中文
            speakChinese(text) {
                if (this.muted) return;
                this.speak(text, 'zh-CN');
            }

            // 核心播放函数
            speak(text, lang = 'en-US') {
                if (this.isSpeaking) {
                    this.speechSynthesis.cancel();
                }

                const utterance = new SpeechSynthesisUtterance(text);
                utterance.lang = lang;

                // 应用声音设置
                const settings = this.voiceSettings[lang] || this.voiceSettings['en-US'];
                utterance.rate = settings.rate;
                utterance.pitch = settings.pitch;
                utterance.volume = settings.volume;

                // 选择最佳语音
                const voices = this.speechSynthesis.getVoices();
                const targetVoice = voices.find(voice => 
                    voice.lang === lang && 
                    voice.name.includes('Female')
                ) || voices.find(voice => voice.lang === lang) || voices[0];

                if (targetVoice) {
                    utterance.voice = targetVoice;
                }

                // 事件监听
                utterance.onstart = () => {
                    this.isSpeaking = true;
                    this.currentUtterance = utterance;
                    this.onSpeechStart(text, lang);
                };

                utterance.onend = () => {
                    this.isSpeaking = false;
                    this.currentUtterance = null;
                    this.onSpeechEnd(text, lang);

                    // 重复播放模式
                    if (this.repeatMode) {
                        setTimeout(() => this.speak(text, lang), 1000);
                    }
                };

                utterance.onerror = (event) => {
                    this.isSpeaking = false;
                    this.currentUtterance = null;
                    console.error('语音播放错误:', event.error);
                    this.onSpeechError(text, lang);
                };

                // 开始播放
                this.speechSynthesis.speak(utterance);
            }

            // 停止当前播放
            stop() {
                if (this.isSpeaking) {
                    this.speechSynthesis.cancel();
                    this.isSpeaking = false;
                    this.currentUtterance = null;
                }
            }

            // 切换自动播放
            toggleAutoPlay() {
                this.autoPlay = !this.autoPlay;
                return this.autoPlay;
            }

            // 切换重复播放
            toggleRepeat() {
                this.repeatMode = !this.repeatMode;
                return this.repeatMode;
            }

            // 切换静音
            toggleMute() {
                this.muted = !this.muted;
                if (this.muted && this.isSpeaking) {
                    this.stop();
                }
                return this.muted;
            }

            // 事件回调
            onSpeechStart(text, lang) {
                console.log(`开始播放: ${text} (${lang})`);
                // 添加播放动画
                const playingElement = document.querySelector('.playing');
                if (playingElement) {
                    playingElement.classList.remove('playing');
                }

                // 根据语言找到对应的元素
                if (lang === 'en-US') {
                    const wordElement = document.getElementById('currentWord');
                    if (wordElement && wordElement.textContent === text) {
                        wordElement.classList.add('playing');
                    }
                } else if (lang === 'zh-CN') {
                    const transElement = document.getElementById('currentTranslation');
                    if (transElement && transElement.textContent === text) {
                        transElement.classList.add('playing');
                    }
                }
            }

            onSpeechEnd(text, lang) {
                console.log(`播放结束: ${text} (${lang})`);
                // 移除播放动画
                const playingElements = document.querySelectorAll('.playing');
                playingElements.forEach(el => el.classList.remove('playing'));
            }

            onSpeechError(text, lang) {
                console.error(`播放失败: ${text} (${lang})`);
                // 可以在这里添加错误提示
            }

            showAudioError(message) {
                alert(message);
            }
        }

