        // ==================== 全局变量 ====================
        let audioSystem;
        let currentWordData;

        // ==================== 初始化 ====================
        document.addEventListener('DOMContentLoaded', function() {
            audioSystem = new AudioSystem();
            initButtons();
            initGame();
        });

        function initButtons() {
            document.getElementById('autoPlayBtn').addEventListener('click', function() {
                const isActive = audioSystem.toggleAutoPlay();
                this.classList.toggle('active', isActive);
                this.innerHTML = isActive ? '<span>🔊</span> 自动播放中' : '<span>🔊</span> 自动播放';
            });

            document.getElementById('repeatBtn').addEventListener('click', function() {
                const isActive = audioSystem.toggleRepeat();
                this.classList.toggle('active', isActive);
                this.innerHTML = isActive ? '<span>🔁</span> 重复中' : '<span>🔁</span> 重复播放';
            });

            document.getElementById('muteBtn').addEventListener('click', function() {
                const isMuted = audioSystem.toggleMute();
                this.classList.toggle('active', isMuted);
                this.innerHTML = isMuted ? '<span>🔇</span> 已静音' : '<span>🔈</span> 静音';
            });
        }

        function initGame() {
            currentWordData = gameData.themes[0].words[0];
            updateCurrentWord();
        }

        // ==================== 界面控制 ====================
        function startGame() {
            document.getElementById('welcomeCard').style.display = 'none';
            document.getElementById('flashcard').style.display = 'flex';
            document.getElementById('btnGroup').style.display = 'block';
            document.getElementById('statsBar').style.display = 'flex';

            if (audioSystem.autoPlay) {
                setTimeout(() => playCurrentWord(), 500);
            }
        }

        function updateCurrentWord() {
            const theme = gameData.themes[gameData.stats.currentTheme];
            currentWordData = theme.words[gameData.stats.currentWordIndex];

            document.getElementById('currentEmoji').textContent = currentWordData.emoji;
            document.getElementById('currentWord').textContent = currentWordData.word;
            document.getElementById('currentTranslation').textContent = currentWordData.chinese;
        }

        function playCurrentWord() {
            audioSystem.speakEnglish(currentWordData.word);
        }

        function playCurrentTranslation() {
            audioSystem.speakChinese(currentWordData.chinese);
        }

        function nextWord() {
            const theme = gameData.themes[gameData.stats.currentTheme];
            gameData.stats.currentWordIndex = (gameData.stats.currentWordIndex + 1) % theme.words.length;

            if (gameData.stats.currentWordIndex === 0) {
                gameData.stats.currentTheme = (gameData.stats.currentTheme + 1) % gameData.themes.length;
                showBadge('theme_complete', '主题完成', '🏆');
            }

            updateCurrentWord();
            updateStats();

            if (audioSystem.autoPlay) {
                setTimeout(() => playCurrentWord(), 300);
            }
        }

        function repeatWord() {
            playCurrentWord();
            setTimeout(() => playCurrentTranslation(), 1500);
        }

        function changeTheme() {
            gameData.stats.currentTheme = (gameData.stats.currentTheme + 1) % gameData.themes.length;
            gameData.stats.currentWordIndex = 0;
            updateCurrentWord();

            const theme = gameData.themes[gameData.stats.currentTheme];
            audioSystem.speakChinese(`切换到${theme.name}主题`);
        }

        function showProgress() {
            const total = gameData.themes.reduce((sum, theme) => sum + theme.words.length, 0);
            const learned = gameData.stats.wordsLearned;
            const percentage = Math.round((learned / total) * 100);

            audioSystem.speakChinese(`你已经学习了${learned}个单词，总共${total}个，完成率${percentage}%`);
            alert(`📊 学习进度\n\n已学单词：${learned}/${total}\n完成率：${percentage}%\n\n继续加油！汪汪队为你骄傲！🐾`);
        }

        function updateStats() {
            gameData.stats.wordsLearned++;
            document.getElementById('wordCount').textContent = gameData.stats.wordsLearned;
            document.getElementById('correctCount').textContent = gameData.stats.correctAnswers;
            document.getElementById('badgeCount').textContent = gameData.stats.badgesEarned;

            if (gameData.stats.wordsLearned % 10 === 0) {
                showBadge('milestone', '学习达人', '🌟');
            }
        }

        function showBadge(id, name, emoji) {
            gameData.stats.badgesEarned++;
            document.getElementById('badgeCount').textContent = gameData.stats.badgesEarned;

            audioSystem.speakChinese(`恭喜你获得${name}徽章！`);

            const badgeMsg = `🏅 恭喜获得新徽章！\n\n${emoji} ${name}\n\n继续保持！汪汪队为你骄傲！🐾`;
            setTimeout(() => alert(badgeMsg), 500);
        }

        function testAudio(lang) {
            if (lang === 'en') {
                audioSystem.speakEnglish('Hello! Welcome to Paw Patrol English World!');
            } else {
                audioSystem.speakChinese('你好！欢迎来到汪汪队英语乐园！');
            }
        }
    </script>
